    /**
     * @method
     * @name bitfinex#fetchMarkets
     * @description retrieves data on all markets for bitfinex
     * @see https://docs.bitfinex.com/reference/rest-public-conf
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object labels = new java.util.ArrayList<Object>(java.util.Arrays.asList("pub:info:pair", "pub:info:pair:futures", "pub:list:pair:securities", "pub:list:pair:margin"));
            Object config = String.join((String)",", (java.util.List<String>)labels);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "config", config );
            }};
            var spotMarketsInfofuturesMarketsInfosecuritiesMarketsIdsmarginIdsVariable = (this.publicGetConfConfig(this.extend(request, parameters))).join();
            var spotMarketsInfo = ((java.util.List<Object>) spotMarketsInfofuturesMarketsInfosecuritiesMarketsIdsmarginIdsVariable).get(0);
            var futuresMarketsInfo = ((java.util.List<Object>) spotMarketsInfofuturesMarketsInfosecuritiesMarketsIdsmarginIdsVariable).get(1);
            var securitiesMarketsIds = ((java.util.List<Object>) spotMarketsInfofuturesMarketsInfosecuritiesMarketsIdsmarginIdsVariable).get(2);
            var marginIds = ((java.util.List<Object>) spotMarketsInfofuturesMarketsInfosecuritiesMarketsIdsmarginIdsVariable).get(3);
            Object markets = this.arrayConcat(spotMarketsInfo, futuresMarketsInfo);
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(markets)); i++)
            {
                Object pairObj = Helpers.GetValue(markets, i);
                Object id = this.safeStringUpper(pairObj, 0);
                Object market = this.safeValue(pairObj, 1, new java.util.HashMap<String, Object>() {{}});
                Object spot = true;
                Object type = null;
                if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(((String)id), "F0"), 0)))
                {
                    spot = false;
                    type = "swap";
                } else
                {
                    type = "spot";
                }
                Object swap = Helpers.isEqual(type, "swap");
                Object baseId = null;
                Object quoteId = null;
                if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(((String)id), ":"), 0)))
                {
                    Object parts = Helpers.split(((String)id), ":");
                    baseId = Helpers.GetValue(parts, 0);
                    quoteId = Helpers.GetValue(parts, 1);
                } else
                {
                    baseId = Helpers.slice(((String)id), 0, 3);
                    quoteId = Helpers.slice(((String)id), 3, 6);
                }
                Object base = this.safeCurrencyCode(baseId);
                Object quote = this.safeCurrencyCode(quoteId);
                Object splitBase = Helpers.split(((String)base), "F0");
                Object splitQuote = Helpers.split(((String)quote), "F0");
                base = ((String)this.safeString(splitBase, 0));
                quote = ((String)this.safeString(splitQuote, 0));
                Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
                // baseId = 'f' + baseId;
                // quoteId = 'f' + quoteId;
                Object settle = null;
                Object settleId = null;
                if (Helpers.isTrue(swap))
                {
                    settle = quote;
                    settleId = quote;
                    symbol = Helpers.add(Helpers.add(symbol, ":"), settle);
                }
                Object minOrderSizeString = this.safeString(market, 3);
                Object maxOrderSizeString = this.safeString(market, 4);
    final Object finalSymbol = symbol;
                final Object finalBase = base;
                final Object finalQuote = quote;
                final Object finalSettle = settle;
                final Object finalBaseId = baseId;
                final Object finalQuoteId = quoteId;
                final Object finalSettleId = settleId;
                final Object finalType = type;
                final Object finalSpot = spot;
                            ((java.util.List<Object>)result).add(new java.util.HashMap<String, Object>() {{
                    put( "id", Helpers.add("t", id) );
                    put( "symbol", finalSymbol );
                    put( "base", finalBase );
                    put( "quote", finalQuote );
                    put( "settle", finalSettle );
                    put( "baseId", finalBaseId );
                    put( "quoteId", finalQuoteId );
                    put( "settleId", finalSettleId );
                    put( "type", finalType );
                    put( "spot", finalSpot );
                    put( "tradfi", BitfinexCore.this.inArray(id, securitiesMarketsIds) );
                    put( "margin", (Helpers.isTrue(finalSpot) && Helpers.isTrue(BitfinexCore.this.inArray(id, marginIds))) );
                    put( "swap", swap );
                    put( "future", false );
                    put( "option", false );
                    put( "active", true );
                    put( "contract", !Helpers.isTrue(finalSpot) );
                    put( "linear", ((Helpers.isTrue(swap))) ? true : null );
                    put( "inverse", ((Helpers.isTrue(swap))) ? false : null );
                    put( "contractSize", ((Helpers.isTrue(swap))) ? BitfinexCore.this.parseNumber("1") : null );
                    put( "expiry", null );
                    put( "expiryDatetime", null );
                    put( "strike", null );
                    put( "optionType", null );
                    put( "precision", new java.util.HashMap<String, Object>() {{
                        put( "amount", Helpers.parseInt("8") );
                        put( "price", Helpers.parseInt("5") );
                    }} );
                    put( "limits", new java.util.HashMap<String, Object>() {{
                        put( "leverage", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                        put( "amount", new java.util.HashMap<String, Object>() {{
                            put( "min", BitfinexCore.this.parseNumber(minOrderSizeString) );
                            put( "max", BitfinexCore.this.parseNumber(maxOrderSizeString) );
                        }} );
                        put( "price", new java.util.HashMap<String, Object>() {{
                            put( "min", BitfinexCore.this.parseNumber("1e-8") );
                            put( "max", null );
                        }} );
                        put( "cost", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                    }} );
                    put( "created", null );
                    put( "info", market );
                }});
            }
            return result;
        });

    }

