            Object response = (this.publicGetConfConfig(this.extend(request, parameters))).join();
            //
            //     [
            //
            //         a list of symbols
            //         ["AAA","ABS","ADA"],
            //
            //         // sym
            //         // maps symbols to their API symbols, BAB > BCH
            //         [
            //             [ "BAB", "BCH" ],
