            //         [
            //             [ "BAB", "Bitcoin Cash" ],
            //             [ "BCH", "Bitcoin Cash" ],
            //             [ "LEO", "Unus Sed LEO" ],
            //             [ "LES", "Unus Sed LEO (EOS)" ],
            //             [ "LET", "Unus Sed LEO (ERC20)" ],
            //             // ...
